import torch
import torch.nn as nn
import timm

class CIFAR100Model(nn.Module):
    def __init__(self, num_classes=100, backbone='convnext_tiny.fb_in22k_ft_in1k', pretrained=True):
        super().__init__()
        self.backbone = timm.create_model(backbone, pretrained=pretrained, num_classes=0)  # no head
        feat_dim = self.backbone.num_features
        self.head = nn.Sequential(
            nn.LayerNorm(feat_dim),
            nn.Dropout(0.3),
            nn.Linear(feat_dim, num_classes)
        )

    def forward(self, x):
        features = self.backbone(x)
        return self.head(features)

def get_model(num_classes=100, pretrained=True):
    return CIFAR100Model(num_classes=num_classes, pretrained=pretrained)
